public  static ETGBillExchangeController construct()
{
    return new ETGBillExchangeController();
}

public static void main(Args    _args)
{
    ETGBillExchangeController       billExchangeController;
    ETGBillExchangeContract         billExchangeContract;
    CustInvoiceJour                 custInvoiceJour;

    billExchangeController    =   ETGBillExchangeController::construct();
    custInvoiceJour                 =   _args.record() as CustInvoiceJour;

    billExchangeController    =   new ETGBillExchangeController(
                                    classStr (ETGBillExchangeService),
                                    methodStr(ETGBillExchangeService , generateReportByGER),
                                    SysOperationExecutionMode::Synchronous);

    billExchangeContract      =   billExchangeController.getDataContractObject();

    billExchangeContract.parmSalesInvoiceId(custInvoiceJour.InvoiceId);
    billExchangeContract.parmSalesId(custInvoiceJour.SalesId);
    billExchangeContract.parmCustInvoiceRecId(custInvoiceJour.RecId);

    billExchangeController.parmArgs(_args);
    billExchangeController.parmShowDialog(false);
    billExchangeController.startOperation();
}
